  9→fn show_and_focus(window: &tauri::WebviewWindow) {
 10→    if let Err(e) = window.center() {
 11→        eprintln!("failed to center window: {e}");
 12→    }
 13→    if let Err(e) = window.show() {
 14→        eprintln!("failed to show window: {e}");
 15→    }
 16→    if let Err(e) = window.set_focus() {
 17→        eprintln!("failed to focus window: {e}");
 18→    }
 19→}
 20→
 21→fn toggle_window(window: &tauri::WebviewWindow) {
 22→    let visible = window.is_visible().unwrap_or(false);
 23→    let focused = window.is_focused().unwrap_or(false);
 24→
 25→    if visible && focused {
 26→        if let Err(e) = window.hide() {
 27→            eprintln!("failed to hide window: {e}");
 28→        }
 29→    } else if visible {
 30→        if let Err(e) = window.set_focus() {
 31→            eprintln!("failed to focus window: {e}");
 32→        }
 33→    } else {
 34→        show_and_focus(window);
 35→    }
 36→}
