 39→pub fn run() {
 40→    tauri::Builder::default()
 41→        .setup(|app| {
 42→            #[cfg(desktop)]
 43→            {
 44→                let shortcut = Shortcut::new(Some(Modifiers::ALT), Code::Space);
 45→                let window = app
 46→                    .get_webview_window("main")
 47→                    .expect("main window not found");
 48→
 49→                let window_for_shortcut = window.clone();
 50→                app.handle().plugin(
 51→                    tauri_plugin_global_shortcut::Builder::new()
 52→                        .with_handler(move |_app, scut, event| {
 53→                            if scut == &shortcut && event.state() == ShortcutState::Pressed {
 54→                                toggle_window(&window_for_shortcut);
 55→                            }
 56→                        })
 57→                        .build(),
 58→                )?;
 59→
 60→                app.global_shortcut().register(shortcut)?;
 61→
 62→                let show_item = MenuItem::with_id(app, "show", "Show Raycast", true, None::<&str>)?;
 63→                let clipboard_item =
 64→                    MenuItem::with_id(app, "clipboard", "Clipboard History", true, None::<&str>)?;
 65→                let snippets_item =
 66→                    MenuItem::with_id(app, "snippets", "Snippets", true, None::<&str>)?;
 67→                let settings_item =
 68→                    MenuItem::with_id(app, "settings", "Settings", true, None::<&str>)?;
 69→                let sep1 = PredefinedMenuItem::separator(app)?;
 70→                let about_item =
 71→                    MenuItem::with_id(app, "about", "About Raycast Clone", true, None::<&str>)?;
 72→                let quit_item = MenuItem::with_id(app, "quit", "Quit", true, None::<&str>)?;
 73→
 74→                let menu = Menu::with_items(
 75→                    app,
 76→                    &[
 77→                        &show_item,
 78→                        &sep1,
 79→                        &clipboard_item,
 80→                        &snippets_item,
 81→                        &settings_item,
 82→                        &PredefinedMenuItem::separator(app)?,
 83→                        &about_item,
 84→                        &quit_item,
 85→                    ],
 86→                )?;
 87→
 88→                let window_for_menu = window.clone();
 89→                let window_for_tray = window.clone();
 90→
 91→                TrayIconBuilder::new()
 92→                    .icon(tauri::image::Image::from_bytes(include_bytes!("../icons/tray-icon.png"))?)
 93→                    .icon_as_template(true)
 94→                    .tooltip("Raycast Clone")
 95→                    .menu(&menu)
 96→                    .show_menu_on_left_click(false)
 97→                    .on_menu_event(move |app, event| match event.id().as_ref() {
 98→                        "show" => {
 99→                            show_and_focus(&window_for_menu);
100→                        }
101→                        "clipboard" | "snippets" | "settings" => {
102→                            show_and_focus(&window_for_menu);
103→                            if let Err(e) =
104→                                app.emit("tray-navigate", event.id().as_ref().to_string())
105→                            {
106→                                eprintln!("failed to emit tray-navigate: {e}");
107→                            }
108→                        }
109→                        "about" => {
110→                            show_and_focus(&window_for_menu);
111→                            if let Err(e) = app.emit("tray-navigate", "about".to_string()) {
112→                                eprintln!("failed to emit tray-navigate: {e}");
113→                            }
114→                        }
115→                        "quit" => {
116→                            app.exit(0);
117→                        }
118→                        _ => {}
119→                    })
120→                    .on_tray_icon_event(move |_tray, event| {
121→                        if let TrayIconEvent::Click {
122→                            button: MouseButton::Left,
123→                            button_state: MouseButtonState::Up,
124→                            ..
125→                        } = event
126→                        {
127→                            toggle_window(&window_for_tray);
128→                        }
129→                    })
130→                    .build(app)?;
131→            }
132→
133→            Ok(())
134→        })
135→        .run(tauri::generate_context!())
136→        .expect("error while running tauri application");
137→}
