 1→import { useCallback, useEffect, useRef } from 'react';
 2→
 3→let isTauri = false;
 4→try {
 5→  isTauri = '__TAURI_INTERNALS__' in window;
 6→} catch {
 7→  // not in Tauri
 8→}
 9→
10→export { isTauri };
11→
12→interface UseWindowOptions {
13→  onShow?: () => void;
14→  onHide?: () => void;
15→  onTrayNavigate?: (target: string) => void;
16→}
17→
18→export function useWindow(options: UseWindowOptions = {}) {
19→  const onShowRef = useRef(options.onShow);
20→  const onHideRef = useRef(options.onHide);
21→  const onTrayNavigateRef = useRef(options.onTrayNavigate);
22→
23→  useEffect(() => {
24→    onShowRef.current = options.onShow;
25→    onHideRef.current = options.onHide;
26→    onTrayNavigateRef.current = options.onTrayNavigate;
27→  });
28→
29→  useEffect(() => {
30→    if (!isTauri) return;
31→
32→    let unlistenFocus: (() => void) | undefined;
33→    let unlistenTray: (() => void) | undefined;
34→    let cancelled = false;
35→
36→    (async () => {
37→      const { getCurrentWindow } = await import('@tauri-apps/api/window');
38→      const { listen } = await import('@tauri-apps/api/event');
39→      const appWindow = getCurrentWindow();
40→
41→      const focusUnsub = await appWindow.onFocusChanged(({
42→        payload: focused,
43→      }) => {
44→        if (focused) {
45→          onShowRef.current?.();
46→        } else {
47→          onHideRef.current?.();
48→        }
49→      });
50→
51→      const trayUnsub = await listen<string>('tray-navigate', event => {
52→        onTrayNavigateRef.current?.(event.payload);
53→      });
54→
55→      if (cancelled) {
56→        focusUnsub();
57→        trayUnsub();
58→      } else {
59→        unlistenFocus = focusUnsub;
60→        unlistenTray = trayUnsub;
61→      }
62→    })();
63→
64→    return () => {
65→      cancelled = true;
66→      unlistenFocus?.();
67→      unlistenTray?.();
68→    };
69→  }, []);
70→
71→  const hideWindow = useCallback(async () => {
72→    if (!isTauri) return;
73→    const { getCurrentWindow } = await import('@tauri-apps/api/window');
74→    await getCurrentWindow().hide();
75→  }, []);
76→
77→  return {
78→    hideWindow,
79→    isTauri,
80→  };
81→}
