 158→export function App() {
 159→  useTheme();
 160→  const [query, setQuery] = useState('');
 161→  const [filterValue, setFilterValue] = useState('all');
 162→  const [selectedIndex, setSelectedIndex] = useState(0);
 163→  const [actionsOpen, setActionsOpen] = useState(false);
 164→  const [quickLookOpen, setQuickLookOpen] = useState(false);
 165→  const { toasts, show: showToast, hide: hideToast } = useToast();
 166→  const { items: hudItems, show: showHUD } = useHUD();
 167→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
 168→  const nav = useNavigationStack<NavViewData>('Raycast');
 169→  const { push } = nav;
 170→  const { favoriteIds, isFavorite, toggleFavorite, moveFavorite } =
 171→    useFavorites();
 172→
 173→  const handleTrayNavigate = useCallback(
 174→    (target: string) => {
 175→      const trayCommandMap: Record<
 176→        string,
 177→        {
 178→          id: string;
 179→          name: string;
 180→        }
 181→      > = {
 182→        clipboard: {
 183→          id: 'clipboard-history',
 184→          name: 'Clipboard History',
 185→        },
 186→        snippets: {
 187→          id: 'snippets',
 188→          name: 'Snippets',
 189→        },
 190→        settings: {
 191→          id: 'settings',
 192→          name: 'Settings',
 193→        },
 194→      };
 195→
 196→      const mapping = trayCommandMap[target];
 197→      if (!mapping) return;
 198→
 199→      const cmd = getCommand(mapping.id);
 200→      if (!cmd?.component) return;
 201→
 202→      nav.popToRoot();
 203→      setQuery('');
 204→      setSelectedIndex(0);
 205→      setActionsOpen(false);
 206→      setQuickLookOpen(false);
 207→      setFilterValue('all');
 208→
 209→      push(mapping.name, {
 210→        type: 'command',
 211→        commandId: mapping.id,
 212→      });
 213→    },
 214→    [
 215→      push,
 216→      nav,
 217→    ],
 218→  );
 219→
 220→  useWindow({
 221→    onShow: () => {
 222→      const input =
 223→        document.querySelector<HTMLInputElement>('.search-bar__input');
 224→      input?.focus();
 225→    },
 226→    onHide: () => {
 227→      setQuery('');
 228→      nav.popToRoot();
 229→      setActionsOpen(false);
 230→      setQuickLookOpen(false);
 231→      setSelectedIndex(0);
 232→      setFilterValue('all');
 233→    },
 234→    onTrayNavigate: handleTrayNavigate,
 235→  });
 236→
 237→  const currentNavData = nav.currentEntry?.data;
 238→  const isRoot = !currentNavData;
 239→  const isFullView =
 240→    currentNavData?.type === 'command' &&
 241→    (getCommand(currentNavData.commandId)?.fullView ?? false);
 242→
 243→  const searchFilterSections: SearchDropdownSection[] = useMemo(
 244→    () => [
 245→      {
 246→        options: [
 247→          {
 248→            label: 'All',
 249→            value: 'all',
 250→          },
 251→        ],
 252→      },
 253→      {
 254→        title: 'Types',
 255→        options: [
 256→          {
 257→            label: 'Commands',
 258→            value: 'commands',
 259→          },
 260→          {
 261→            label: 'Applications',
 262→            value: 'applications',
 263→          },
 264→        ],
 265→      },
 266→    ],
 267→    [],
 268→  );
 269→
 270→  useEffect(() => {
 271→    if (nav.stackDepth === 0) {
 272→      setQuery('');
 273→      setFilterValue('all');
 274→      setSelectedIndex(0);
 275→      setActionsOpen(false);
 276→      setQuickLookOpen(false);
 277→    }
 278→  }, [nav.stackDepth]);
 279→
 280→  const registrySections = useMemo(() => getSections(), []);
 281→
 282→  const filtered = useMemo(() => {
 283→    let sections = registrySections;
