 304→            }
 305→            if (filterValue === 'applications') {
 306→              return s.title === 'Applications'
 307→                ? s
 308→                : {
 309→                    ...s,
 310→                    items: [],
 311→                  };
 312→            }
 313→            return s;
 314→          })
 315→          .filter(s => s.items.length > 0)
 316→      : result;
