 329→      );
 330→      if (filteredFavs.length > 0) {
 331→        const favIds = new Set(filteredFavs.map(f => f.id));
 332→        const dedupedSections = filteredResult
 333→          .map(s => ({
 334→            ...s,
 335→            items: s.items.filter(item => !favIds.has(item.id)),
 336→          }))
 337→          .filter(s => s.items.length > 0);
 338→        return [
 339→          {
 340→            title: 'Favorites',
 341→            items: filteredFavs,
 342→          },
 343→          ...dedupedSections,
 344→        ];
 345→      }
 346→      return filteredResult;
 347→    }
 348→
 349→    if (favoriteItems.length > 0) {
 350→      const favIds = new Set(favoriteIds);
 351→      const dedupedSections = filteredResult
 352→        .map(s => ({
 353→          ...s,
 354→          items: s.items.filter(item => !favIds.has(item.id)),
 355→        }))
 356→        .filter(s => s.items.length > 0);
 357→      return [
 358→        {
 359→          title: 'Favorites',
 360→          items: favoriteItems,
 361→        },
 362→        ...dedupedSections,
 363→      ];
 364→    }
 365→
 366→    return filteredResult;
 367→  }, [
 368→    query,
 369→    filterValue,
 370→    favoriteIds,
 371→    registrySections,
 372→  ]);
 373→
 374→  const calculatorResult = useMemo(() => {
 375→    if (!isRoot || !query.trim()) return null;
 376→    return evaluate(query);
 377→  }, [
 378→    query,
 379→    isRoot,
