 403→  const selectedItem = isRoot ? allItems[selectedIndex] : undefined;
 404→
 405→  const handleQueryChange = useCallback((value: string) => {
 406→    setQuery(value);
 407→    setSelectedIndex(0);
 408→    setActionsOpen(false);
