 410→
 411→  const handleFilterChange = useCallback((value: string) => {
 412→    setFilterValue(value);
 413→    setSelectedIndex(0);
 414→  }, []);
 415→
 416→  const handleActiveIndexChange = useCallback((index: number) => {
 417→    setSelectedIndex(index);
 418→    setActionsOpen(false);
 419→  }, []);
 420→
 421→  const handleDrillIn = useCallback(() => {
 422→    const item = allItems[selectedIndex];
 423→    if (!item) return;
 424→
 425→    setActionsOpen(false);
 426→
 427→    if (item.id === '__calculator__') {
 428→      showHUD({
 429→        icon: <ClipboardHUDIcon />,
 430→        title: `Copied ${calculatorResult}`,
 431→      });
 432→      return;
 433→    }
 434→
 435→    const cmd = getCommand(item.id);
 436→
 437→    if (cmd?.component) {
 438→      push(cmd.name, {
 439→        type: 'command',
 440→        commandId: cmd.id,
 441→      });
 442→      setQuery('');
 443→      setSelectedIndex(0);
 444→    } else if (item.detail) {
 445→      push(item.title, {
 446→        type: 'detail',
 447→        item,
 448→      });
 449→      setQuery('');
 450→      showToast({
 451→        style: 'success',
 452→        title: `Opened ${item.title}`,
 453→      });
 454→    } else {
 455→      showToast({
 456→        style: 'success',
 457→        title: `Opened ${item.title}`,
