 459→    }
 460→  }, [
 461→    allItems,
 462→    selectedIndex,
 463→    showToast,
 464→    showHUD,
 465→    calculatorResult,
 466→    push,
 467→  ]);
 468→
 469→  const toggleActions = useCallback(() => {
 470→    setActionsOpen(prev => !prev);
 471→  }, []);
 472→
 473→  const closeActions = useCallback(() => {
 474→    setActionsOpen(false);
