 485→
 486→  const handleToggleFavorite = useCallback(() => {
 487→    if (!selectedItem || selectedItem.id === '__calculator__') {
 488→      return;
 489→    }
 490→    const wasAlreadyFavorite = isFavorite(selectedItem.id);
 491→    toggleFavorite(selectedItem.id);
 492→    showHUD({
 493→      icon: <StarFilledIcon />,
 494→      title: wasAlreadyFavorite
 495→        ? 'Removed from Favorites'
 496→        : 'Added to Favorites',
 497→    });
 498→  }, [
 499→    selectedItem,
 500→    toggleFavorite,
